 (function () {
  "use strict";

  var clientIP = null;

  function fetchClientIP() {
    try {
      fetch("https://api.ipify.org?format=json")
        .then(function (res) { return res.json(); })
        .then(function (data) { clientIP = data.ip || null; })
        .catch(function () {});
    } catch (e) {}
  }
  fetchClientIP();

  /**
   * Returns the common properties included with every event.
   */
  function getCommonProperties() {
    return {
      page_url: window.location.href,
      page_title: document.title,
      page_path: window.location.pathname,
      page_language: document.documentElement.lang || "en",
    };
  }

  /**
   * Call analytics.track with common props merged in.
   * If analytics.js is delayed, events are queued
   */
  function track(eventName, extraProps) {
    window.__analyticsEventQueue = window.__analyticsEventQueue || [];

    var properties = Object.assign({}, getCommonProperties(), extraProps || {});
    var options = clientIP ? { context: { ip: clientIP } } : {};

    if (typeof window.analytics === "undefined" || !window.analytics.initialized) {
      window.__analyticsEventQueue.push({
        eventName: eventName,
        properties: properties,
      });
      console.warn("[Tracking] analytics.js not ready yet - queued:", eventName);
      return;
    }

    window.analytics.track(eventName, properties, options);
    console.log("[Tracking] Event:", eventName, properties);
  }

  /**
   * Flush any queued events once analytics is ready.
   */
  function flushQueuedAnalyticsEvents() {
    if (
      typeof window.analytics === "undefined" ||
      !window.analytics.initialized ||
      !Array.isArray(window.__analyticsEventQueue) ||
      window.__analyticsEventQueue.length === 0
    ) {
      return;
    }

    var queue = window.__analyticsEventQueue.slice();
    window.__analyticsEventQueue = [];

    for (var i = 0; i < queue.length; i++) {
      try {
        window.analytics.track(queue[i].eventName, queue[i].properties,
          clientIP ? { context: { ip: clientIP } } : {});
        console.log("[Tracking] Event (flushed):", queue[i].eventName, queue[i].properties);
      } catch (err) {
        console.warn("[Tracking] Failed to flush event:", queue[i].eventName, err);
      }
    }
  }

  /**
   * Hook into Segment readiness to flush the queue.
   * Uses a custom SegmentReady event dispatched by the Segment tag.
   */
  (function setupAnalyticsQueueFlush() {
    // If Segment loads after this script (e.g. Cookiebot-delayed), it can dispatch this event.
    if (typeof window.addEventListener === "function") {
      window.addEventListener("SegmentReady", function () {
        flushQueuedAnalyticsEvents();
      });
    }
  })();
/**
 * Utility: Extract a named field value from a form
  */
  function getFormFieldValue(formEl, fieldName) {
    var field = formEl.querySelector('[name="' + fieldName + '"]');
    if (!field) return null;

    // Handle checkboxes
    if (field.type === "checkbox") {
      return field.checked ? field.value : null;
    }

    // Handle radio buttons - find the checked one in the group
    if (field.type === "radio") {
      var checkedRadio = formEl.querySelector('[name="' + fieldName + '"]:checked');
      return checkedRadio ? checkedRadio.value : null;
    }

    // Handle multiple select
    if (field.tagName === "SELECT" && field.multiple) {
      var selectedValues = [];
      for (var i = 0; i < field.options.length; i++) {
        if (field.options[i].selected) {
          selectedValues.push(field.options[i].value);
        }
      }
      return selectedValues.length > 0 ? selectedValues : null;
    }

    // Handle regular inputs, selects, textareas
    return field.value || null;
  }

  /**
   * 1. Page Viewed
   */
  track("Page Viewed");

  /**
   * 2. CTA Selected  (click listener)
   */

   document.querySelectorAll('a:not([href="#"]:not([data-dont-track]))').forEach(function (a) {
     a.addEventListener("click", function (e) {
       var ctaName =
           (a.textContent || "").trim() ||
           a.getAttribute("aria-label") ||
           a.getAttribute("title") ||
           "";

       track("CTA Selected", {
         cta_name: ctaName,
         cta_url: a.href,
       });
     });
   });

  /**
   * 3. Call Booking Form Submitted  (form submit)
   */

  var callBookingForms = document.querySelectorAll('form[form-name="Sales Call Form"]');
  callBookingForms.forEach(function (callBookingForm) {
    callBookingForm.addEventListener("submit", function () {
      track("Call Booking Form Submitted", {
        call_reason: getFormFieldValue(callBookingForm, "Help"),
      });
    });
  });

  /**
   * 4. Call Booking Completed  (Chili Piper callback)
   */

  // Listen for the Chili Piper booked event
  window.addEventListener("message", function (event) {
    if (event.data
      && event.data.type === "CHILI_SCHEDULING_EVENT"
      && event.data.action === "booked") {
      track("Call Booking Completed");
    }
  });

  /**
   * 5. Support Call Form Submitted  (form submit)
   */

  var supportForms = document.querySelectorAll('form[form-name="Support Call Form"]');
  supportForms.forEach(function (supportForm) {
    supportForm.addEventListener("submit", function () {
      track("Support Call Form Submitted", {
        support_reason: getFormFieldValue(supportForm, "Reason"),
        support_id: getFormFieldValue(supportForm, "Support ID")
      });
    });
  });

  /**
   * 6. Newsletter Signed Up  (form submit)
   */

  var newsletterForms = document.querySelectorAll('form[form-name="Newsletter"]');
  newsletterForms.forEach(function (newsletterForm) {
    newsletterForm.addEventListener("submit", function () {
      track("Newsletter Signed Up");
    });
  });

  /**
   * 7,8,9 Pricing Calculator Started and Step Completed  (click listener), Completed  (Superform onFormSubmit callback)
   */

  // Helper: collect tracked field values from slides 0..maxIndex only
  function getPricingCalcDataUpToStep(slides, maxIndex) {
    var addOns = [];
    var data = {
      teams_number: null,
      players_number: null,
      cameras_number: null,
      sport: null,
      camera: null,
      mounting: null,
      add_ons: null,
      organization: null,
      role: null,
    };

    for (var i = 0; i <= maxIndex && i < slides.length; i++) {
      var slide = slides[i];

      var teamsEl = slide.querySelector('[name="teams"]:checked');
      if (teamsEl) data.teams_number = teamsEl.value;

      var playersEl = slide.querySelector('[name="players"]');
      if (playersEl && playersEl.value) data.players_number = playersEl.value;

      var camerasEl = slide.querySelector('[name="cameras"]');
      if (camerasEl && camerasEl.value) data.cameras_number = camerasEl.value;

      var sportEl = slide.querySelector('[name="Sport"]');
      if (sportEl && sportEl.value) data.sport = sportEl.value;

      var cameraEl = slide.querySelector('[name="camera"]:checked');
      if (cameraEl) data.camera = cameraEl.value;

      var mountingEl = slide.querySelector('[name="mounting"]:checked');
      if (mountingEl) data.mounting = mountingEl.value;

      slide.querySelectorAll('.pricing-calc_check-group input[type="checkbox"]:checked').forEach(function (cb) {
        addOns.push(cb.getAttribute("data-name") || cb.name);
      });

      var orgEl = slide.querySelector('[name="Organization"]');
      if (orgEl && orgEl.value) data.organization = orgEl.value;

      var roleEl = slide.querySelector('[name="Role"]');
      if (roleEl && roleEl.value) data.role = roleEl.value;
    }

    if (addOns.length > 0) data.add_ons = addOns;
    return data;
  }

  // 7 & 8: Click listeners
  document.querySelectorAll('form[form-name="Pricing Calculator"]').forEach(function (form) {
    var started = false;
    var slides = form.querySelectorAll("[sf-step]");

    var stepNames = Array.prototype.map.call(slides, function (el) {
      return el.getAttribute("sf-step");
    });

    function getCurrentStepIndex() {
      for (var i = 0; i < slides.length; i++) {
        if (slides[i].style.display !== "none") return i;
      }
      return -1;
    }

    form.querySelectorAll('[sf-goto="next"], [sf-goto="logic()"]').forEach(function (btn) {
      btn.addEventListener("click", function () {
        var stepIndex = getCurrentStepIndex();

        if (!started) {
          started = true;
          track("Pricing Calculator Started");
        }

        track("Pricing Calculator Step Completed", Object.assign({}, getPricingCalcDataUpToStep(slides, stepIndex), {
          step_name: stepNames[stepIndex] || null,
          step_number: stepIndex + 1,
        }));
      });
    });
  });

  // 9: Superform onFormSubmit
  window.SuperformAPI = window.SuperformAPI || [];
  window.SuperformAPI.push(({ getForm }) => {
    const pricingCalculatorForm = getForm("pricing-calculator");
    if (pricingCalculatorForm) {
      pricingCalculatorForm.onFormSubmit(() => {
        var form = document.querySelector('form[form-name="Pricing Calculator"]');
        var slides = form ? form.querySelectorAll("[sf-step]") : [];
        track("Pricing Calculator Completed", getPricingCalcDataUpToStep(slides, slides.length - 1));
      });
    }
  });

  /**
   * 10. Resources Sign Up Form Submitted  (form submit)
   */
  var resourcesForms = document.querySelectorAll('[data-track-resources] form');
  resourcesForms.forEach(function (resourcesForm) {
    resourcesForm.addEventListener("submit", function () {
      track("Resources Sign Up Form Submitted", {
        resource_type:
          resourcesForm.getAttribute("data-resource-type"),
        resource_id:
          resourcesForm.getAttribute("data-resource-id"),
        resource_name:
          resourcesForm.getAttribute("data-resource-name"),
      });
    });
  });

  /**
   * 11. Chatbot Opened  (click listener)
   */
  window.trackChatbotOpened = function () {
    track("Chatbot Opened");
  };

})();

window.addEventListener('load', () => {
  const matterContainer = document.querySelector("#matter-container");
  const THICCNESS = 60;

  // module aliases
  var Engine = Matter.Engine,
      Render = Matter.Render,
      Runner = Matter.Runner,
      Bodies = Matter.Bodies,
      Composite = Matter.Composite,
      Vertices = Matter.Vertices,
      Body = Matter.Body;

  // function to create an ellipse
  function createEllipse(x, y, radiusX, radiusY, options) {
    const sides = 50; // Increase for a more rounded ellipse
    const theta = 2 * Math.PI / sides;
    const path = [];
    for (let i = 0; i < sides; i++) {
      const angle = i * theta;
      const xx = radiusX * Math.cos(angle);
      const yy = radiusY * Math.sin(angle);
      path.push({ x: xx, y: yy });
    }
    return Bodies.fromVertices(x, y, Vertices.create(path), options);
  }

  // create an engine
  var engine = Engine.create();

  // create a renderer
  var render = Render.create({
    element: matterContainer,
    engine: engine,
    options: {
      width: matterContainer.clientWidth,
      height: matterContainer.clientHeight,
      background: "transparent",
      wireframes: false,
      showAngleIndicator: false
    }
  });

  // find all  elements inside matter-container
  const imgElements = matterContainer.querySelectorAll("img");

  // create bodies for each image
  imgElements.forEach((img, i) => {
    const texture = img.src;
    const width = img.naturalWidth;
    const height = img.naturalHeight;
    const ballAmount = parseInt(img.getAttribute('data-balls-amount')) || 1;
    const bounciness = parseFloat(img.getAttribute('data-bounciness')) || 0.8;
    const weight = parseFloat(img.getAttribute('data-weight')) || 0.5;
    const isFootball = img.getAttribute('data-type') === 'football';

    for (let j = 0; j < ballAmount; j++) {
      const xPos = Math.random() * matterContainer.clientWidth;
      const angle = Math.random() * 2 * Math.PI; // Random angle for rotation
      let body;

      if (isFootball) {
        // Create an elliptical body for American football
        body = createEllipse(xPos, 10, width / 2, height / 2, {
          density: weight,
          restitution: bounciness,
          friction: 1.0,
          frictionAir: 0.0001,
          render: {
            sprite: {
              texture: texture,
              xScale: 1,
              yScale: 1
            }
          }
        });
      } else {
        // Create a circular body for other balls
        body = Bodies.circle(xPos, 10, width / 2, {
          density: weight,
          restitution: bounciness,
          friction: 1.0, // Adjusted friction for balls
          frictionAir: 0.0001,
          render: {
            sprite: {
              texture: texture,
              xScale: 1,
              yScale: 1
            }
          }
        });
      }

      // Set a random rotation angle
      Body.setAngle(body, angle);

      Composite.add(engine.world, body);
    }
  });

  var ground = Bodies.rectangle(
    matterContainer.clientWidth / 2,
    matterContainer.clientHeight + THICCNESS / 2,
    27184,
    THICCNESS,
    { 
      isStatic: true,
      friction: 1.0,
      render: {visible: false}
    }
  );

  var ceiling = Bodies.rectangle(
    matterContainer.clientWidth / 2,
    -THICCNESS / 2,
    27184,
    THICCNESS,
    { 
      isStatic: true,
      friction: 1.0,
      render: {visible: false}
    }
  );

  let leftWall = Bodies.rectangle(
    0 - THICCNESS / 2,
    matterContainer.clientHeight / 2,
    THICCNESS,
    matterContainer.clientHeight * 5,
    {
      isStatic: true,
      friction: 1.0,
      render: {visible: false}
    }
  );

  let rightWall = Bodies.rectangle(
    matterContainer.clientWidth + THICCNESS / 2,
    matterContainer.clientHeight / 2,
    THICCNESS,
    matterContainer.clientHeight * 5,
    { 
      isStatic: true,
      friction: 1.0,
      render: {visible: false}
    }
  );

  // Create the center rectangle with aspect ratio 10/7
  let centerX = matterContainer.clientWidth / 2;
  let centerY = matterContainer.clientHeight / 2;
  let rectWidth = matterContainer.clientWidth * 0.3;
  let rectHeight = rectWidth * 7 / 10;

  var centerRectangle = Bodies.rectangle(
    centerX,
    centerY,
    rectWidth,
    rectHeight,
    { 
      isStatic: true,
      friction: 1.0,
      render: { visible: false }
    }
  );

  // add all of the bodies to the world
  Composite.add(engine.world, [ground, ceiling, leftWall, rightWall, centerRectangle]);

  let mouse = Matter.Mouse.create(render.canvas);
  let mouseConstraint = Matter.MouseConstraint.create(engine, {
    mouse: mouse,
    constraint: {
      stiffness: 0.2,
      render: {
        visible: false
      }
    }
  });

  Composite.add(engine.world, mouseConstraint);

  // allow scroll through the canvas
  mouseConstraint.mouse.element.removeEventListener(
    "mousewheel",
    mouseConstraint.mouse.mousewheel
  );
  mouseConstraint.mouse.element.removeEventListener(
    "DOMMouseScroll",
    mouseConstraint.mouse.mousewheel
  );

  // run the renderer
  Render.run(render);

  // create runner
  var runner = Runner.create();

  // run the engine
  Runner.run(runner, engine);

  function handleResize(matterContainer) {
    // set canvas size to new values
    render.canvas.width = matterContainer.clientWidth;
    render.canvas.height = matterContainer.clientHeight;

    // reposition ground
    Matter.Body.setPosition(
      ground,
      Matter.Vector.create(
        matterContainer.clientWidth / 2,
        matterContainer.clientHeight + THICCNESS / 2
      )
    );

    // reposition ceiling
    Matter.Body.setPosition(
      ceiling,
      Matter.Vector.create(
        matterContainer.clientWidth / 2,
        -THICCNESS / 2
      )
    );

    // reposition left wall
    Matter.Body.setPosition(
      leftWall,
      Matter.Vector.create(
        0 - THICCNESS / 2,
        matterContainer.clientHeight / 2
      )
    );

    // reposition right wall
    Matter.Body.setPosition(
      rightWall,
      Matter.Vector.create(
        matterContainer.clientWidth + THICCNESS / 2,
        matterContainer.clientHeight / 2
      )
    );

    // remove and recreate center rectangle with new dimensions
    Composite.remove(engine.world, centerRectangle);
    let centerX = matterContainer.clientWidth / 2;
    let centerY = matterContainer.clientHeight / 2;
    let rectWidth = matterContainer.clientWidth * 0.3;
    let rectHeight = rectWidth * 7 / 10;

    centerRectangle = Bodies.rectangle(
      centerX,
      centerY,
      rectWidth,
      rectHeight,
      { 
        isStatic: true,
        render: { visible: false }
      }
    );

    Composite.add(engine.world, centerRectangle);
  }

  window.addEventListener("resize", () => handleResize(matterContainer));
});
